pipeline = [
    {'$match': {'status': 'active'}},
    {'$group': {
        '_id': '$country',
        'count': {'$sum': 1},
        'avg_age': {'$avg': '$age'}
    }},
    {'$sort': {'count': -1}},
    {'$limit': 10}
]

for result in users.aggregate(pipeline):
    print(f"{result['_id']}: {result['count']} users, avg age {result['avg_age']:.1f}")
